const DEFAULT_MUSIC_VOLUME = 0.75;
let fxAudioContext = null;
let answerAdvanceTimer = null;
let fullscreenButtonVisible = false;
const AUTO_ADVANCE_STORAGE_KEY = "quizAutoAdvanceEnabled";

function getFxAudioContext() {
  const AudioCtx = window.AudioContext || window.webkitAudioContext;
  if (!AudioCtx) return null;
  if (!fxAudioContext) fxAudioContext = new AudioCtx();
  if (fxAudioContext.state === "suspended") {
    fxAudioContext.resume().catch(() => {});
  }
  return fxAudioContext;
}

function playSynthSequence(sequence) {
  const ctx = getFxAudioContext();
  if (!ctx || !Array.isArray(sequence)) return;

  let startAt = ctx.currentTime + 0.01;

  sequence.forEach((note, index) => {
    const oscillator = ctx.createOscillator();
    const gainNode = ctx.createGain();
    const duration = Math.max(0.04, Number(note.duration) || 0.1);
    const gainValue = Math.max(0.01, Number(note.gain) || 0.03);

    oscillator.type = note.type || "sine";
    oscillator.frequency.setValueAtTime(note.freq || 440, startAt);

    gainNode.gain.setValueAtTime(0.0001, startAt);
    gainNode.gain.linearRampToValueAtTime(gainValue, startAt + 0.015);
    gainNode.gain.exponentialRampToValueAtTime(0.0001, startAt + duration);

    oscillator.connect(gainNode);
    gainNode.connect(ctx.destination);

    oscillator.start(startAt);
    oscillator.stop(startAt + duration + 0.02);

    startAt += duration * (index === sequence.length - 1 ? 0.92 : 0.8);
  });
}

function playCorrectSound() {
  try {
    playSynthSequence(SOUND_FX.correct);
  } catch (error) {}
}

function playWrongSound() {
  try {
    playSynthSequence(SOUND_FX.wrong);
  } catch (error) {}
}

function clearAnswerAdvanceTimer() {
  if (answerAdvanceTimer) {
    clearTimeout(answerAdvanceTimer);
    answerAdvanceTimer = null;
  }
}

function isAutoAdvanceEnabled() {
  try {
    return localStorage.getItem(AUTO_ADVANCE_STORAGE_KEY) === "1";
  } catch (error) {
    return false;
  }
}

function setAutoAdvanceEnabled(enabled) {
  try {
    localStorage.setItem(AUTO_ADVANCE_STORAGE_KEY, enabled ? "1" : "0");
  } catch (error) {}
}

function toggleAutoAdvance() {
  const nextValue = !isAutoAdvanceEnabled();
  setAutoAdvanceEnabled(nextValue);
  if (!nextValue) clearAnswerAdvanceTimer();

  const type = currentGame?.type;
  if (type === "aviation") renderAviationGame();
  else if (type === "geography") renderGeographyGame();
  else if (type === "flag") renderFlagGame();
  else if (type === "capital") renderCapitalGame();
  else if (type === "delta") renderDeltaGame();
  else if (type === "plate") renderPlateGame();
  else if (type === "province") renderProvinceGame();
  else if (type === "neighborprovince") renderNeighborProvinceGame();
  else if (type === "englishword") renderEnglishWordGame();
}

function scheduleAutoAdvance(game, renderGame, onComplete, isCorrect) {
  clearAnswerAdvanceTimer();
  if (!isAutoAdvanceEnabled() || !game) return;

  const questionIndex = game.currentQuestion;
  const waitTime = isCorrect ? 1000 : 2000;

  answerAdvanceTimer = setTimeout(() => {
    answerAdvanceTimer = null;
    if (!currentGame || currentGame !== game) return;
    if (game.currentQuestion !== questionIndex) return;
    if (!canMoveNext(game)) return;
    advanceGameQuestion(game, onComplete);
    renderGame();
  }, waitTime);
}

function formatTimeLabel(seconds) {
  const safe = Math.max(0, Math.floor(Number(seconds) || 0));
  const minutes = Math.floor(safe / 60);
  const remaining = safe % 60;
  return `${minutes}:${String(remaining).padStart(2, "0")}`;
}

function updateMusicTimeline(kind, audio) {
  const slider = document.getElementById(`${kind}-music-progress`);
  const label = document.getElementById(`${kind}-music-time`);
  if (!slider || !label) return;

  const duration = Number.isFinite(audio?.duration) ? audio.duration : 0;
  const currentTime = Number.isFinite(audio?.currentTime) ? audio.currentTime : 0;
  slider.max = String(Math.max(1, Math.floor(duration || 1)));
  slider.value = String(Math.min(Math.floor(currentTime), Math.max(1, Math.floor(duration || 1))));
  slider.disabled = !audio;
  label.textContent = `${formatTimeLabel(currentTime)} / ${formatTimeLabel(duration)}`;
}

function bindMusicProgressControls(kind, getAudio) {
  const slider = document.getElementById(`${kind}-music-progress`);
  if (!slider) return;

  const audio = getAudio();
  updateMusicTimeline(kind, audio);

  if (slider.__progressBoundFor !== kind) {
    slider.addEventListener("input", () => {
      const activeAudio = getAudio();
      if (!activeAudio) return;
      const nextTime = Number(slider.value);
      if (!Number.isFinite(nextTime)) return;
      activeAudio.currentTime = Math.max(0, nextTime);
      updateMusicTimeline(kind, activeAudio);
    });
    slider.__progressBoundFor = kind;
  }

  if (!audio || audio.__timelineEventsBound) return;

  const refreshAll = () => {
    refreshAllMusicUIs();
  };

  audio.addEventListener("loadedmetadata", refreshAll);
  audio.addEventListener("timeupdate", refreshAll);
  audio.addEventListener("play", refreshAll);
  audio.addEventListener("pause", refreshAll);
  audio.addEventListener("seeked", refreshAll);
  audio.addEventListener("durationchange", refreshAll);
  audio.__timelineEventsBound = true;
}

function ensureTopbarActions() {
  const topbarInner = document.querySelector("#main-topbar .topbar-inner");
  if (!topbarInner) return null;
  let actions = topbarInner.querySelector(".topbar-actions");
  if (!actions) {
    actions = document.createElement("div");
    actions.className = "topbar-actions";
    topbarInner.appendChild(actions);
  }
  return actions;
}

function updateFullscreenButton() {
  const actions = ensureTopbarActions();
  if (!actions) return;
  actions.innerHTML = "";
  if (!fullscreenButtonVisible) return;

  const isFullscreen = !!document.fullscreenElement;
  const button = document.createElement("button");
  button.type = "button";
  button.id = "fullscreen-toggle";
  button.className = "topbar-icon-btn";
  button.innerHTML = isFullscreen ? "⤢ <span>Tam Ekrandan Çık</span>" : "⛶ <span>Tam Ekran</span>";
  button.addEventListener("click", async () => {
    try {
      if (document.fullscreenElement) await document.exitFullscreen();
      else await document.documentElement.requestFullscreen();
    } catch (error) {}
  });
  actions.appendChild(button);
}

function setFullscreenButtonVisible(visible) {
  fullscreenButtonVisible = !!visible;
  updateFullscreenButton();
}

document.addEventListener("fullscreenchange", updateFullscreenButton);

const appScreen = document.getElementById("app-screen");

function reloadSiteToHome() {
  window.location.reload();
}

document.addEventListener("click", (event) => {
  const backHomeTrigger = event.target.closest("#back-home, #back-home-coming");
  if (!backHomeTrigger) return;
  event.preventDefault();
  event.stopPropagation();
  if (typeof event.stopImmediatePropagation === "function") {
    event.stopImmediatePropagation();
  }
  reloadSiteToHome();
}, true);

if (appScreen) {
  appScreen.addEventListener("click", (event) => {
    const finishButton = event.target.closest("#finish-btn");
    if (finishButton) {
      if (currentGame?.type === "province") {
        event.preventDefault();
        event.stopPropagation();
        finishProvinceGame();
        return;
      }
      if (currentGame?.type === "neighborprovince") {
        event.preventDefault();
        event.stopPropagation();
        finishNeighborProvinceGame();
        return;
      }
    }

    const restartProvinceButton = event.target.closest("#restart-province");
    if (restartProvinceButton) {
      event.preventDefault();
      event.stopPropagation();
      restartProvinceLikeGame();
      return;
    }

    const restartNeighborProvinceButton = event.target.closest("#restart-neighbor-province");
    if (restartNeighborProvinceButton) {
      event.preventDefault();
      event.stopPropagation();
      restartProvinceLikeGame("neighborprovince");
      return;
    }

    const backHomeButton = event.target.closest("#back-home");
    if (backHomeButton) {
      event.preventDefault();
      event.stopPropagation();
      renderHome();
      return;
    }
  });
}
const clickAudio = window.clickAudio || null;
let activeNameModalCleanup = null;

function playClickSound() {
  try {
    if (!clickAudio || typeof clickAudio.play !== "function") return;
    clickAudio.currentTime = 0;
    clickAudio.play().catch(() => {});
  } catch (error) {}
}

function fadeOutAndStopAudio(audio, duration = 5000) {
  if (!audio) return;
  if (audio.__fadeTimer) clearInterval(audio.__fadeTimer);

  const startVolume = Number.isFinite(audio.volume) ? audio.volume : 0.75;
  const steps = 22;
  const stepTime = Math.max(40, Math.round(duration / steps));
  let step = 0;

  audio.__fadeTimer = setInterval(() => {
    step += 1;
    const nextVolume = Math.max(0, startVolume * (1 - step / steps));
    audio.volume = nextVolume;

    if (step >= steps) {
      clearInterval(audio.__fadeTimer);
      audio.__fadeTimer = null;
      audio.pause();
      audio.currentTime = 0;
      audio.volume = startVolume;
    }
  }, stepTime);
}


// 👇 TAM BURAYA EKLE
const aviationTracks = [
  "audio/Volkan Hoca.mp3"
];

let aviationAudio = null;
let aviationTrackIndex = 0;

function getAviationTrackName(src) {
  if (!src) return "-";
  const fileName = src.split("/").pop();
  return fileName.replace(/\.mp3$/i, "");
}

function updateAviationMusicInfo() {
  const info = document.getElementById("aviation-music-info");
  const toggleBtn = document.getElementById("aviation-music-toggle");

  if (info) {
    info.textContent = `Çalan: ${aviationAudio ? getAviationTrackName(aviationTracks[aviationTrackIndex]) : "-"}`;
  }

  if (toggleBtn) {
    toggleBtn.textContent = aviationAudio && !aviationAudio.paused
      ? "♫ Müziği Kapat"
      : "♫ Müziği Aç";
  }
}

function playAviationMusic() {
  if (aviationAudio) {
    aviationAudio.pause();
    aviationAudio.currentTime = 0;
  }

  aviationAudio = new Audio(aviationTracks[aviationTrackIndex]);
  aviationAudio.volume = DEFAULT_MUSIC_VOLUME;
  applyMusicVolume("aviation", DEFAULT_MUSIC_VOLUME);

  aviationAudio.addEventListener("ended", () => {
    nextAviationTrack();
  });

  aviationAudio.play().catch(() => {});
  updateAviationMusicInfo();
}

function stopAviationMusic() {
  if (aviationAudio) {
    fadeOutAndStopAudio(aviationAudio, 5000);
  }
  updateAviationMusicInfo();
}

function toggleAviationMusic() {
  if (!aviationAudio) {
    startUniversalMusic("aviation");
    return;
  }

  if (aviationAudio.paused) {
    aviationAudio.play().catch(() => {});
  } else {
    aviationAudio.pause();
  }

  updateAviationMusicInfo();
}

function nextAviationTrack() {
  aviationTrackIndex = (aviationTrackIndex + 1) % aviationTracks.length;
  playAviationMusic();
}

function prevAviationTrack() {
  aviationTrackIndex = (aviationTrackIndex - 1 + aviationTracks.length) % aviationTracks.length;
  playAviationMusic();
}


