/* -----------------------------
   COĞRAFYA MÜZİK SİSTEMİ
------------------------------ */
let geographyAudio = null;
let geographyPlaylist = [
  { file: "audio/Volkan Hoca.mp3", name: "Volkan Hoca" },
  { file: "audio/geo38.mp3", name: "Sata Andagi" },
  { file: "audio/geo1.mp3", name: "Hikaru Nara" },
  { file: "audio/geo3.mp3", name: "Harry Styles - Golden" },
  { file: "audio/geo13.mp3", name: "iya iya" },
  { file: "audio/geo27.mp3", name: "JANE DOE - Minachu" },
  { file: "audio/geo32.mp3", name: "manifest - Yaşanacaksa" },
  { file: "audio/geo43.mp3", name: "TRT Çocuk" },
  


];
let geographyTrackIndex = 0;
let geographyMusicEnabled = true;
let geographyLoopEnabled = false;
let geographyShuffleEnabled = true;
let geographyPlaylistOpen = false;
let geographyShufflePool = [];
let geographyShuffleHistory = [];

function ensureGeographyAudio() {
  if (geographyAudio) return geographyAudio;

  geographyAudio = new Audio();
  geographyAudio.preload = "metadata";
  geographyAudio.volume = DEFAULT_MUSIC_VOLUME;
  applyMusicVolume("geography", DEFAULT_MUSIC_VOLUME);

  geographyAudio.addEventListener("ended", () => {
    if (geographyPlaylist.length === 0) return;

    if (geographyLoopEnabled) {
      setGeographyTrack(geographyTrackIndex, true);
      return;
    }

    if (geographyShuffleEnabled) {
      const randomIndex = getNextGeographyShuffleIndex();
      setGeographyTrack(randomIndex, true);
      return;
    }

    geographyTrackIndex = (geographyTrackIndex + 1) % geographyPlaylist.length;
    setGeographyTrack(geographyTrackIndex, true);
  });

  geographyAudio.addEventListener("error", () => {
    const brokenTrack = geographyPlaylist[geographyTrackIndex];
    console.error("Müzik yüklenemedi:", brokenTrack?.file || "bilinmeyen dosya");
    refreshAllMusicUIs();
  });

  return geographyAudio;
}

function setGeographyTrack(index, shouldPlay = geographyMusicEnabled, resetTime = true) {
  if (geographyPlaylist.length === 0) return null;

  geographyTrackIndex = (index + geographyPlaylist.length) % geographyPlaylist.length;
  registerPlayedGeographyTrack(geographyTrackIndex);
  const audio = ensureGeographyAudio();
  audio.loop = geographyLoopEnabled;
  const currentTrack = geographyPlaylist[geographyTrackIndex];

  if (!currentTrack) return audio;

  const nextSrc = String(currentTrack.file || "").trim();
  const resolvedSrc = new URL(nextSrc, window.location.href).href;
  if (audio.src !== resolvedSrc) {
    audio.src = nextSrc;
    audio.load();
  }

  if (resetTime) audio.currentTime = 0;
  if (shouldPlay) {
    const playAttempt = audio.play();
    if (playAttempt && typeof playAttempt.catch === "function") {
      playAttempt.catch(() => {
        refreshAllMusicUIs();
      });
    }
  }

  refreshAllMusicUIs();
  bindMusicProgressControls("geography", () => geographyAudio);
  return audio;
}

function rebuildGeographyShufflePool(excludeIndex = null) {
  geographyShufflePool = geographyPlaylist
    .map((_, index) => index)
    .filter((index) => index !== excludeIndex);

  for (let i = geographyShufflePool.length - 1; i > 0; i -= 1) {
    const j = Math.floor(Math.random() * (i + 1));
    [geographyShufflePool[i], geographyShufflePool[j]] = [geographyShufflePool[j], geographyShufflePool[i]];
  }
}

function registerPlayedGeographyTrack(index) {
  if (!Number.isInteger(index) || index < 0) return;

  geographyShuffleHistory = geographyShuffleHistory.filter((item) => item !== index);
  geographyShuffleHistory.push(index);

  if (geographyShuffleHistory.length > geographyPlaylist.length) {
    geographyShuffleHistory = geographyShuffleHistory.slice(-geographyPlaylist.length);
  }

  geographyShufflePool = geographyShufflePool.filter((item) => item !== index);
}

function resetGeographyPlaylist() {
  geographyTrackIndex = 0;
  geographyShuffleHistory = [];
  rebuildGeographyShufflePool();
  if (geographyAudio) {
    geographyAudio.pause();
    geographyAudio.currentTime = 0;
    geographyAudio.removeAttribute("src");
    geographyAudio.load();
    updateMusicTimeline("geography", geographyAudio);
  }
}

function stopGeographyMusic(resetPlaylist = false) {
  if (geographyAudio) {
    fadeOutAndStopAudio(geographyAudio, 5000);
    if (resetPlaylist) {
      geographyTrackIndex = 0;
      window.setTimeout(() => {
        if (!geographyAudio) return;
        geographyAudio.currentTime = 0;
        geographyAudio.src = geographyPlaylist[0]?.file || "";
        geographyAudio.load();
        updateMusicTimeline("geography", geographyAudio);
        updateMusicInfo();
      }, 5200);
    }
  } else if (resetPlaylist) {
    geographyTrackIndex = 0;
  }
}

function playGeographyMusic() {
  if (!geographyMusicEnabled || geographyPlaylist.length === 0) return;
  setGeographyTrack(geographyTrackIndex, true, false);
}

function getNextGeographyShuffleIndex() {
  if (geographyPlaylist.length <= 1) return 0;

  if (!Array.isArray(geographyShufflePool) || geographyShufflePool.length === 0) {
    rebuildGeographyShufflePool(geographyTrackIndex);
  }

  if (geographyShufflePool.length === 0) return geographyTrackIndex;

  return geographyShufflePool.shift();
}

function getRandomGeographyStartIndex() {
  if (geographyPlaylist.length <= 1) return 0;

  const lastPlayedIndex = geographyShuffleHistory.length
    ? geographyShuffleHistory[geographyShuffleHistory.length - 1]
    : geographyTrackIndex;

  if (!Array.isArray(geographyShufflePool) || geographyShufflePool.length === 0) {
    rebuildGeographyShufflePool(lastPlayedIndex);
  }

  if (geographyShufflePool.length === 0) {
    const fallbackIndexes = geographyPlaylist
      .map((_, index) => index)
      .filter((index) => index !== lastPlayedIndex);

    if (fallbackIndexes.length === 0) return 0;
    return fallbackIndexes[Math.floor(Math.random() * fallbackIndexes.length)];
  }

  return geographyShufflePool.shift();
}

function toggleGeographyLoop() {
  geographyLoopEnabled = !geographyLoopEnabled;
  refreshAllMusicUIs();
}

function toggleGeographyShuffle() {
  geographyShuffleEnabled = !geographyShuffleEnabled;
  refreshAllMusicUIs();
}

function toggleGeographyPlaylistPanel() {
  geographyPlaylistOpen = !geographyPlaylistOpen;
  rerenderCurrentGameView();
}

function closeGeographyPlaylistPanel() {
  if (!geographyPlaylistOpen) return;
  geographyPlaylistOpen = false;
  rerenderCurrentGameView();
}

function selectGeographyTrack(index) {
  if (geographyPlaylist.length === 0) return;
  geographyPlaylistOpen = false;
  geographyMusicEnabled = true;
  setGeographyTrack(index, true, true);
  rerenderCurrentGameView();
}

function toggleGeographyMusic() {
  geographyMusicEnabled = !geographyMusicEnabled;

  if (!geographyMusicEnabled) {
    if (geographyAudio) geographyAudio.pause();
  } else {
    playGeographyMusic();
  }

  refreshAllMusicUIs();
}

function nextGeographyTrack() {
  if (geographyPlaylist.length === 0) return;
  const nextIndex = geographyShuffleEnabled ? getNextGeographyShuffleIndex() : geographyTrackIndex + 1;
  setGeographyTrack(nextIndex, true);
}

function prevGeographyTrack() {
  if (geographyPlaylist.length === 0) return;
  if (geographyShuffleEnabled) {
    setGeographyTrack(getNextGeographyShuffleIndex(), true);
    return;
  }
  setGeographyTrack(geographyTrackIndex - 1, true);
}

function updateGeographyLoopButton() {
  const btn = document.getElementById("geography-music-loop");
  if (!btn) return;
  btn.textContent = geographyLoopEnabled ? "🔁 Loop Açık" : "🔁 Loop Kapalı";
  btn.classList.toggle("is-active", geographyLoopEnabled);
}

function updateGeographyShuffleButton() {
  const btn = document.getElementById("geography-music-shuffle");
  if (!btn) return;
  btn.textContent = geographyShuffleEnabled ? "🔀 Karışık Açık" : "🔀 Karışık Kapalı";
  btn.classList.toggle("is-active", geographyShuffleEnabled);
}

function updateGeographyPlaylistButton() {
  const btn = document.getElementById("geography-music-playlist");
  if (!btn) return;
  btn.textContent = geographyPlaylistOpen ? "📂 Playlist Açık" : "📂 Playlist";
  btn.classList.toggle("is-active", geographyPlaylistOpen);
}

function bindGeographyExtraMusicControls() {
  const loopBtn = document.getElementById("geography-music-loop");
  const shuffleBtn = document.getElementById("geography-music-shuffle");
  const playlistBtn = document.getElementById("geography-music-playlist");
  const playlistCloseBtn = document.getElementById("geography-playlist-close");
  const playlistPanel = document.getElementById("geography-playlist-panel");

  if (loopBtn) {
    loopBtn.addEventListener("click", () => {
      toggleGeographyLoop();
      const audio = ensureGeographyAudio();
      audio.loop = geographyLoopEnabled;
    });
  }

  if (shuffleBtn) {
    shuffleBtn.addEventListener("click", () => {
      toggleGeographyShuffle();
    });
  }

  if (playlistBtn) {
    playlistBtn.addEventListener("click", () => {
      toggleGeographyPlaylistPanel();
    });
  }

  if (playlistCloseBtn) {
    playlistCloseBtn.addEventListener("click", () => {
      closeGeographyPlaylistPanel();
    });
  }

  if (playlistPanel) {
    playlistPanel.querySelectorAll("[data-track-index]").forEach((item) => {
      item.addEventListener("click", () => {
        const index = Number(item.getAttribute("data-track-index"));
        if (!Number.isFinite(index)) return;
        selectGeographyTrack(index);
        renderGeographyGame();
      });
    });
  }
}

function renderGeographyPlaylistMarkup() {
  if (!geographyPlaylistOpen) return "";

  const items = geographyPlaylist.map((track, index) => `
    <button type="button" class="geo-playlist-item ${index === geographyTrackIndex ? "active" : ""}" data-track-index="${index}">
      <span class="geo-playlist-index">${index + 1}</span>
      <span class="geo-playlist-name">${track.name}</span>
      ${index === geographyTrackIndex ? '<span class="geo-playlist-now">Çalıyor</span>' : ""}
    </button>
  `).join("");

  return `
    <div class="geo-playlist-panel" id="geography-playlist-panel">
      <div class="geo-playlist-header">
        <strong>Playlist</strong>
        <button type="button" class="geo-playlist-close" id="geography-playlist-close">✕</button>
      </div>
      <div class="geo-playlist-list">${items}</div>
    </div>
  `;
}

function updateMusicButton() {
  const btn = document.getElementById("geography-music-toggle");
  if (!btn) return;

  btn.textContent = geographyMusicEnabled ? "♫ Müziği Kapat" : "♫ Müziği Aç";
}

function updateMusicInfo() {
  const info = document.getElementById("geography-music-info");
  if (!info) return;

  const currentTrack = geographyPlaylist[geographyTrackIndex];
  const trackName = currentTrack?.name || "Müzik";
  info.textContent = `Çalan: ${trackName}`;
}

const UNIVERSAL_MUSIC_KINDS = ["aviation", "geography", "plate", "delta", "capital", "flag", "englishword", "province", "neighborprovince"];

function isUniversalMusicKind(kind) {
  return UNIVERSAL_MUSIC_KINDS.includes(kind);
}

function rerenderCurrentGameView() {
  const type = currentGame?.type;
  if (type === "aviation") renderAviationGame();
  else if (type === "geography") renderGeographyGame();
  else if (type === "flag") renderFlagGame();
  else if (type === "capital") renderCapitalGame();
  else if (type === "delta") renderDeltaGame();
  else if (type === "plate") renderPlateGame();
  else if (type === "province") renderProvinceGame();
  else if (type === "neighborprovince") renderNeighborProvinceGame();
  else if (type === "englishword") renderEnglishWordGame();
}

function refreshAllMusicUIs() {
  updateMusicInfo();
  updateMusicButton();
  updateGeographyLoopButton();
  updateGeographyShuffleButton();
  updateGeographyPlaylistButton();
  updateMusicTimeline("geography", geographyAudio);
  syncMusicSlider("geography");

  UNIVERSAL_MUSIC_KINDS.forEach((kind) => {
    updateUniversalMusicInfo(kind);
    updateUniversalMusicButton(kind);
    updateUniversalMusicLoopButton(kind);
    updateUniversalMusicShuffleButton(kind);
    updateUniversalMusicPlaylistButton(kind);
    updateMusicTimeline(kind, geographyAudio);
    syncMusicSlider(kind);
  });
}

function updateUniversalMusicInfo(kind) {
  const info = document.getElementById(`${kind}-music-info`);
  if (!info) return;
  const currentTrack = geographyPlaylist[geographyTrackIndex];
  const trackName = currentTrack?.name || "Müzik";
  info.textContent = `Çalan: ${trackName}`;
}

function updateUniversalMusicButton(kind) {
  const btn = document.getElementById(`${kind}-music-toggle`);
  if (!btn) return;
  btn.textContent = geographyMusicEnabled ? "♫ Müziği Kapat" : "♫ Müziği Aç";
}

function updateUniversalMusicLoopButton(kind) {
  const btn = document.getElementById(`${kind}-music-loop`);
  if (!btn) return;
  btn.textContent = geographyLoopEnabled ? "🔁 Loop Açık" : "🔁 Loop Kapalı";
  btn.classList.toggle("is-active", geographyLoopEnabled);
}

function updateUniversalMusicShuffleButton(kind) {
  const btn = document.getElementById(`${kind}-music-shuffle`);
  if (!btn) return;
  btn.textContent = geographyShuffleEnabled ? "🔀 Karışık Açık" : "🔀 Karışık Kapalı";
  btn.classList.toggle("is-active", geographyShuffleEnabled);
}

function updateUniversalMusicPlaylistButton(kind) {
  const btn = document.getElementById(`${kind}-music-playlist`);
  if (!btn) return;
  btn.textContent = geographyPlaylistOpen ? "📂 Playlist Açık" : "📂 Playlist";
  btn.classList.toggle("is-active", geographyPlaylistOpen);
}

function renderUniversalMusicPlaylistMarkup(kind) {
  if (!geographyPlaylistOpen) return "";

  const items = geographyPlaylist.map((track, index) => `
    <button type="button" class="geo-playlist-item ${index === geographyTrackIndex ? "active" : ""}" data-track-index="${index}">
      <span class="geo-playlist-index">${index + 1}</span>
      <span class="geo-playlist-name">${track.name}</span>
      ${index === geographyTrackIndex ? '<span class="geo-playlist-now">Çalıyor</span>' : ""}
    </button>
  `).join("");

  return `
    <div class="geo-playlist-panel" id="${kind}-playlist-panel">
      <div class="geo-playlist-header">
        <strong>Playlist</strong>
        <button type="button" class="geo-playlist-close" id="${kind}-playlist-close">✕</button>
      </div>
      <div class="geo-playlist-list">${items}</div>
    </div>
  `;
}

function renderUniversalMusicBar(kind) {
  return `
    <div class="geo-music-bar">
      <div class="geo-music-left">
        <span class="geo-music-chip">🎵 Arka Plan Müziği</span>
        <span class="geography-music-info" id="${kind}-music-info">Çalan: -</span>
      </div>
      <div class="geo-music-actions">
        <div class="geo-music-row geo-music-row-top">
          <div class="music-slider-stack geo-slider-time"><label class="music-slider-label">Süre</label><input type="range" min="0" max="1" value="0" class="music-progress-slider" id="${kind}-music-progress" aria-label="Müzik süresi"><span class="music-time-label" id="${kind}-music-time">0:00 / 0:00</span></div>
          <div class="music-slider-stack geo-slider-volume"><label class="music-slider-label">Ses</label><input type="range" min="0" max="100" value="75" class="music-volume-slider" id="${kind}-music-volume" aria-label="Müzik sesi"></div>
          <button class="secondary-btn" id="${kind}-music-toggle">♫ Müziği Kapat</button>
          <button class="secondary-btn" id="${kind}-music-playlist">📂 Playlist</button>
        </div>
        <div class="geo-music-row geo-music-row-bottom">
          <button class="secondary-btn" id="${kind}-music-prev">⏮ Önceki</button>
          <button class="secondary-btn" id="${kind}-music-next">⏭ Sonraki</button>
          <button class="secondary-btn" id="${kind}-music-loop">🔁 Loop Kapalı</button>
          <button class="secondary-btn" id="${kind}-music-shuffle">🔀 Karışık Kapalı</button>
        </div>
      </div>
      ${renderUniversalMusicPlaylistMarkup(kind)}
    </div>
  `;
}

function bindUniversalMusicControls(kind) {
  bindMusicControls(kind, toggleGeographyMusic, prevGeographyTrack, nextGeographyTrack);
  bindMusicProgressControls(kind, () => geographyAudio);

  const loopBtn = document.getElementById(`${kind}-music-loop`);
  const shuffleBtn = document.getElementById(`${kind}-music-shuffle`);
  const playlistBtn = document.getElementById(`${kind}-music-playlist`);
  const playlistCloseBtn = document.getElementById(`${kind}-playlist-close`);
  const playlistPanel = document.getElementById(`${kind}-playlist-panel`);

  if (loopBtn) {
    loopBtn.addEventListener("click", () => {
      toggleGeographyLoop();
      const audio = ensureGeographyAudio();
      audio.loop = geographyLoopEnabled;
      updateUniversalMusicLoopButton(kind);
    });
  }

  if (shuffleBtn) {
    shuffleBtn.addEventListener("click", () => {
      toggleGeographyShuffle();
      updateUniversalMusicShuffleButton(kind);
    });
  }

  if (playlistBtn) {
    playlistBtn.addEventListener("click", () => {
      geographyPlaylistOpen = !geographyPlaylistOpen;
      rerenderCurrentGameView();
    });
  }

  if (playlistCloseBtn) {
    playlistCloseBtn.addEventListener("click", () => {
      geographyPlaylistOpen = false;
      rerenderCurrentGameView();
    });
  }

  if (playlistPanel) {
    playlistPanel.querySelectorAll("[data-track-index]").forEach((item) => {
      item.addEventListener("click", () => {
        const index = Number(item.getAttribute("data-track-index"));
        if (!Number.isFinite(index)) return;
        geographyPlaylistOpen = false;
        geographyMusicEnabled = true;
        setGeographyTrack(index, true, true);
        rerenderCurrentGameView();
      });
    });
  }

  updateUniversalMusicInfo(kind);
  updateUniversalMusicButton(kind);
  updateUniversalMusicLoopButton(kind);
  updateUniversalMusicShuffleButton(kind);
  updateUniversalMusicPlaylistButton(kind);
  syncMusicSlider(kind);
  updateMusicTimeline(kind, geographyAudio);
}

function startUniversalMusic(kind) {
  geographyMusicEnabled = true;
  geographyShuffleEnabled = true;
  geographyLoopEnabled = false;
  geographyPlaylistOpen = false;

  if (aviationAudio) {
    aviationAudio.pause();
    aviationAudio.currentTime = 0;
  }

  const audio = ensureGeographyAudio();
  audio.pause();
  audio.currentTime = 0;

  const startIndex = getRandomGeographyStartIndex();
  applyMusicVolume(kind, getMusicVolume(kind, DEFAULT_MUSIC_VOLUME));
  setGeographyTrack(startIndex, true, true);
  refreshAllMusicUIs();
}

function stopUniversalMusic(resetPlaylist = false) {
  stopGeographyMusic(resetPlaylist);
}

/* -----------------------------
   TOPBAR
------------------------------ */
function setTopbar(title, subtitle, mode = "left") {
  const titleEl = document.getElementById("topbar-title");
  const subtitleEl = document.getElementById("topbar-subtitle");
  const topbar = document.getElementById("main-topbar");

  if (titleEl) titleEl.textContent = title;
  if (subtitleEl) subtitleEl.textContent = subtitle;

  if (topbar) {
    topbar.classList.remove("topbar-left", "topbar-center");
    topbar.classList.add(mode === "center" ? "topbar-center" : "topbar-left");
  }

  updateFullscreenButton();
}

