function getSavedPlayerName() {
  try {
    return (localStorage.getItem("quizPlayerName") || "").trim();
  } catch (error) {
    return "";
  }
}

function cleanupNameModal() {
  if (typeof activeNameModalCleanup === "function") {
    const fn = activeNameModalCleanup;
    activeNameModalCleanup = null;
    fn();
  }
}

function requestPlayerName() {
  cleanupNameModal();
  const previous = getSavedPlayerName();

  return new Promise((resolve) => {
    const overlay = document.createElement("div");
    overlay.className = "player-name-modal";
    overlay.innerHTML = `
      <div class="player-name-dialog">
        <div class="player-name-badge">Oyuncu Girişi</div>
        <h3>Oyuncu adını gir</h3>
        <p>Skorun bu isimle tabloya kaydedilecek.</p>
        <input id="player-name-input" type="text" maxlength="24" placeholder="Örn: Ege" value="${previous.replace(/"/g, "&quot;")}" />
        <div class="player-name-actions">
          <button class="secondary-btn" id="player-name-cancel">Vazgeç</button>
          <button id="player-name-confirm">Oyuna Başla</button>
        </div>
      </div>
    `;

    document.body.appendChild(overlay);

    const input = overlay.querySelector("#player-name-input");
    const confirmBtn = overlay.querySelector("#player-name-confirm");
    const cancelBtn = overlay.querySelector("#player-name-cancel");

    const close = (value) => {
      overlay.remove();
      activeNameModalCleanup = null;
      resolve(value);
    };

    const submit = () => {
      const name = (input.value || "").trim().slice(0, 24);
      if (!name) {
        input.focus();
        input.classList.add("input-error-shake");
        setTimeout(() => input.classList.remove("input-error-shake"), 420);
        return;
      }
      try {
        localStorage.setItem("quizPlayerName", name);
      } catch (error) {}
      close(name);
    };

    confirmBtn.addEventListener("click", submit);
    cancelBtn.addEventListener("click", () => close(null));
    overlay.addEventListener("click", (event) => {
      if (event.target === overlay) close(null);
    });
    input.addEventListener("keydown", (event) => {
      if (event.key === "Enter") submit();
      if (event.key === "Escape") close(null);
    });

    activeNameModalCleanup = () => overlay.remove();

    setTimeout(() => {
      input.focus();
      input.select();
    }, 20);
  });
}

async function getPlayerName() {
  return await requestPlayerName();
}


async function requestGameSetup(totalQuestionCount = 25) {
  const playerName = await getPlayerName();
  if (!playerName) return null;

  const questionLimit = await requestQuestionLimit(totalQuestionCount);
  if (questionLimit === null) return null;

  return {
    playerName,
    questionLimit,
    isInfinite: false
  };
}

