function buildQuestionSet(sourceQuestions, questionLimit) {
  const source = Array.isArray(sourceQuestions) ? sourceQuestions : [];
  const shuffled = shuffleArray(source);

  if (questionLimit === Infinity) {
    return shuffled;
  }

  return shuffled.slice(0, Math.min(questionLimit, shuffled.length));
}

function getQuestionDisplayTotal(game) {
  return game.isInfinite ? "∞" : game.questions.length;
}

function getQuestionProgressPercent(game) {
  if (game.isInfinite) {
    const cycleSize = Math.max(10, Math.min((game.sourceQuestions || game.questions || []).length || 10, 25));
    return (((game.currentQuestion % cycleSize) + 1) / cycleSize) * 100;
  }

  return ((game.currentQuestion + 1) / game.questions.length) * 100;
}

function advanceGameQuestion(game, onComplete) {
  if (!game) return;

  if (game.currentQuestion < game.questions.length - 1) {
    game.currentQuestion += 1;
    return;
  }

  if (game.isInfinite) {
    const extraBatch = shuffleArray([...(game.sourceQuestions || [])]);
    if (!extraBatch.length) {
      onComplete();
      return;
    }

    const startIndex = game.questions.length;
    game.questions.push(...extraBatch);
    game.selectedAnswers.push(...new Array(extraBatch.length).fill(null));
    game.currentQuestion = startIndex;
    return;
  }

  onComplete();
}

function isSkippedAnswer(value) {
  return value === "__SKIPPED__";
}

function isAnsweredValue(value) {
  return value !== null && typeof value !== "undefined" && !isSkippedAnswer(value);
}

function canMoveNext(game) {
  if (!game) return false;
  const selected = game.selectedAnswers?.[game.currentQuestion];
  return isAnsweredValue(selected) || isSkippedAnswer(selected);
}

function handleNextQuestion(game, renderGame, onComplete) {
  clearAnswerAdvanceTimer();
  if (!game || !canMoveNext(game)) return;
  advanceGameQuestion(game, onComplete);
  renderGame();
}

function handleSkipQuestion(game, renderGame, onComplete) {
  clearAnswerAdvanceTimer();
  if (!game) return;
  game.score -= 2;
  game.selectedAnswers[game.currentQuestion] = "__SKIPPED__";
  updateHighScore(game);
  advanceGameQuestion(game, onComplete);
  renderGame();
}

function renderQuestionNav(game, finishText = "Testi Bitir") {
  const isLastQuestion = game.currentQuestion >= game.questions.length - 1;
  const selected = game.selectedAnswers[game.currentQuestion];
  const answered = isAnsweredValue(selected);
  const skipState = isSkippedAnswer(selected);
  const onlyFinish = isLastQuestion && (answered || skipState);
  const skipDisabled = answered ? 'disabled' : '';
  const finishDisabled = '';
  const nextDisabled = !answered && !skipState ? 'disabled' : '';
  const autoAdvanceEnabled = isAutoAdvanceEnabled();
  const autoAdvanceLabel = autoAdvanceEnabled ? "Oto Geçiş: Açık" : "Oto Geçiş: Kapalı";

  if (onlyFinish) {
    return `
      <div class="auto-advance-row">
        <button type="button" class="auto-advance-toggle ${autoAdvanceEnabled ? "enabled" : ""}" id="auto-advance-toggle">${autoAdvanceLabel}</button>
      </div>
      <div class="nav-row nav-row-finish-only">
        <button type="button" class="nav-btn finish-btn" id="finish-btn">${finishText}</button>
      </div>
    `;
  }

  return `
    <div class="auto-advance-row">
      <button type="button" class="auto-advance-toggle ${autoAdvanceEnabled ? "enabled" : ""}" id="auto-advance-toggle">${autoAdvanceLabel}</button>
      <div class="auto-advance-hint">Doğruysa 1 sn, yanlışsa 2 sn sonra geçer.</div>
    </div>
    <div class="nav-row">
      <button type="button" class="nav-btn" id="prev-btn" ${game.currentQuestion === 0 ? "disabled" : ""}>← Önceki</button>
      <div class="nav-actions-right">
        <button type="button" class="nav-btn skip-btn" id="skip-btn" ${skipDisabled}>Boş Geç (-2)</button>
        ${isLastQuestion
          ? `<button type="button" class="nav-btn finish-btn" id="finish-btn" ${finishDisabled}>${finishText}</button>`
          : `<button type="button" class="nav-btn" id="next-btn" ${nextDisabled}>Sonraki →</button>`}
      </div>
    </div>
  `;
}

function bindAutoAdvanceToggle() {
  const autoAdvanceToggle = document.getElementById("auto-advance-toggle");
  if (autoAdvanceToggle) autoAdvanceToggle.addEventListener("click", toggleAutoAdvance);
}

function getLeaderboard(gameType) {
  try {
    const saved = JSON.parse(localStorage.getItem(LEADERBOARD_KEYS[gameType]) || "[]");
    return Array.isArray(saved) ? saved : [];
  } catch (error) {
    return [];
  }
}

function saveLeaderboard(gameType, rows) {
  try {
    localStorage.setItem(LEADERBOARD_KEYS[gameType], JSON.stringify(rows));
  } catch (error) {}
}

function getGameCounts(game) {
  const answers = Array.isArray(game?.selectedAnswers) ? game.selectedAnswers : [];
  let correct = 0;
  let wrong = 0;

  answers.forEach((selected, index) => {
    if (selected === null || typeof selected === "undefined" || isSkippedAnswer(selected)) return;

    if (game.type === "flag" || game.type === "aviation" || game.type === "geography") {
      const q = game.questions[index];
      if (q && selected === q.correct) correct++;
      else wrong++;
      return;
    }

    if (game.type === "capital") {
      const q = game.questions[index];
      if (q && selected === q.capital) correct++;
      else wrong++;
      return;
    }

    if (game.type === "delta") {
      const q = game.questions[index];
      if (q && selected === q.name) correct++;
      else wrong++;
      return;
    }

    if (game.type === "plate") {
      const q = game.questions[index];
      if (q && selected === q.plate) correct++;
      else wrong++;
      return;
    }

    if (game.type === "province") {
      const q = game.questions[index];
      if (q && selected === q.city) correct++;
      else wrong++;
      return;
    }
  });

  return { correct, wrong };
}

function saveGameResult(game) {
  if (!game || !game.type || !game.playerName) return;
  const counts = getGameCounts(game);
  game.correctCount = counts.correct;
  game.wrongCount = counts.wrong;

  const leaderboard = getLeaderboard(game.type);
  const existingIndex = leaderboard.findIndex(item => item.playerName.toLowerCase() === game.playerName.toLowerCase());
  const entry = {
    playerName: game.playerName,
    score: game.score,
    correct: counts.correct,
    wrong: counts.wrong,
    updatedAt: Date.now()
  };

  if (existingIndex >= 0) {
    if (leaderboard[existingIndex].score >= entry.score) return;
    leaderboard[existingIndex] = entry;
  } else {
    leaderboard.push(entry);
  }

  leaderboard.sort((a, b) => b.score - a.score || b.correct - a.correct || a.wrong - b.wrong || a.playerName.localeCompare(b.playerName, "tr"));
  saveLeaderboard(game.type, leaderboard.slice(0, 50));
}

function getHighScoreEntry(gameType) {
  const leaderboard = getLeaderboard(gameType);
  return leaderboard.length ? leaderboard[0] : null;
}

function getHighScoreLabel(gameType) {
  const top = getHighScoreEntry(gameType);
  if (!top) return { score: 0, playerName: "-" };
  return { score: top.score, playerName: top.playerName };
}

function renderStatsRow(game) {
  const high = getHighScoreLabel(game.type);
  return `
    <div class="compact-stats single-row-stats">
      <div class="mini-stat"><span>Oyuncu</span><strong>${game.playerName || "-"}</strong></div>
      <div class="mini-stat"><span>Soru</span><strong>${game.currentQuestion + 1} / ${getQuestionDisplayTotal(game)}</strong></div>
      <div class="mini-stat"><span>Puan</span><strong>${game.score}</strong></div>
      <div class="mini-stat high-score-stat"><span>En Yüksek Puan</span><strong>${high.score}</strong><em>${high.playerName}</em></div>
    </div>
  `;
}


function renderResultSummary(title, game, total, message, restartId) {
  const counts = getGameCounts(game);
  game.correctCount = counts.correct;
  game.wrongCount = counts.wrong;
  saveGameResult(game);
  const high = getHighScoreLabel(game.type);
  const leaderboard = getLeaderboard(game.type);
  const rows = leaderboard.length
    ? leaderboard.slice(0, 10).map((item, index) => `
        <tr>
          <td>${index + 1}</td>
          <td>${item.playerName}</td>
          <td>${item.score}</td>
          <td>${item.correct}</td>
          <td>${item.wrong}</td>
        </tr>
      `).join("")
    : `<tr><td colspan="5" class="leaderboard-empty">Henüz skor yok.</td></tr>`;

  return `
    <div class="result-box result-box-enhanced">
      <div class="result-actions result-actions-top">
        <button type="button" id="${restartId}">Yeniden Başlat</button>
        <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      </div>
      <h2>${title}</h2>
      <p class="result-score">Toplam Puanın: <strong>${game.score}${game.isInfinite ? "" : ` / ${total}`}</strong></p>
      <div class="result-stats-grid result-stats-grid-large">
        <div class="result-stat-pill"><span>Oyuncu</span><strong>${game.playerName || "-"}</strong></div>
        <div class="result-stat-pill"><span>Doğru</span><strong>${counts.correct}</strong></div>
        <div class="result-stat-pill"><span>Yanlış</span><strong>${counts.wrong}</strong></div>
        <div class="result-stat-pill"><span>En Yüksek</span><strong>${high.score}</strong><em>${high.playerName}</em></div>
      </div>
      <p class="result-message">${message}</p>
      <div class="leaderboard-panel">
        <h3>Skor Tablosu</h3>
        <div class="leaderboard-table-wrap">
          <table class="leaderboard-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Oyuncu</th>
                <th>Puan</th>
                <th>Doğru</th>
                <th>Yanlış</th>
              </tr>
            </thead>
            <tbody>${rows}</tbody>
          </table>
        </div>
      </div>
    </div>
  `;
}

function openLeaderboard(gameType) {
  const meta = GAME_META[gameType];
  if (!meta) return;
  const rows = getLeaderboard(gameType);
  const rowHtml = rows.length
    ? rows.slice(0, 10).map((item, index) => `
        <tr>
          <td>${index + 1}</td>
          <td>${item.playerName}</td>
          <td>${item.score}</td>
          <td>${item.correct}</td>
          <td>${item.wrong}</td>
        </tr>
      `).join("")
    : `<tr><td colspan="5" class="leaderboard-empty">Henüz skor yok.</td></tr>`;

  appScreen.innerHTML = `
    <div class="result-box leaderboard-box">
      <h2>${meta.icon} ${meta.title} Skor Tablosu</h2>
      <div class="leaderboard-table-wrap">
        <table class="leaderboard-table">
          <thead>
            <tr>
              <th>#</th>
              <th>Oyuncu</th>
              <th>Puan</th>
              <th>Doğru</th>
              <th>Yanlış</th>
            </tr>
          </thead>
          <tbody>${rowHtml}</tbody>
        </table>
      </div>
      <p class="leaderboard-note">Site güncelleme aldığında skor tabloları sıfırlanabilir veya bozulabilir.</p>
      <div class="result-actions">
        <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      </div>
    </div>
  `;

  const btn = document.getElementById("back-home");
  if (btn) btn.addEventListener("click", renderHome);
}

function attachLeaderboardButtons() {
  document.querySelectorAll(".leaderboard-trigger").forEach(btn => {
    btn.addEventListener("click", () => {
      const gameType = btn.dataset.game;
      openLeaderboard(gameType);
    });
  });
}

function initializeMusicDefaults() {
  try {
    UNIVERSAL_MUSIC_KINDS.forEach((kind) => {
      localStorage.setItem(`quizMusicVolume_${kind}`, String(DEFAULT_MUSIC_VOLUME));
    });
  } catch (error) {}
}

function applyMusicVolume(kind, value) {
  const safeValue = Math.max(0, Math.min(1, Number(value)));
  try {
    localStorage.setItem(`quizMusicVolume_${kind}`, String(safeValue));
  } catch (error) {}
  if (isUniversalMusicKind(kind) && geographyAudio) geographyAudio.volume = safeValue;
  if (kind === "aviation" && aviationAudio) aviationAudio.volume = safeValue;
}

function getMusicVolume(kind, fallback = 0.75) {
  try {
    const saved = Number(localStorage.getItem(`quizMusicVolume_${kind}`));
    return Number.isFinite(saved) ? Math.max(0, Math.min(1, saved)) : fallback;
  } catch (error) {
    return fallback;
  }
}

function syncMusicSlider(kind) {
  const slider = document.getElementById(`${kind}-music-volume`);
  if (slider) slider.value = String(Math.round(getMusicVolume(kind) * 100));
}

initializeMusicDefaults();

function bindMusicControls(kind, toggleFn, prevFn, nextFn) {
  const toggle = document.getElementById(`${kind}-music-toggle`);
  const prev = document.getElementById(`${kind}-music-prev`);
  const next = document.getElementById(`${kind}-music-next`);
  const slider = document.getElementById(`${kind}-music-volume`);
  const timelineBinder = () => {
    if (isUniversalMusicKind(kind)) bindMusicProgressControls(kind, () => geographyAudio);
    if (kind === "aviation" && !isUniversalMusicKind(kind)) bindMusicProgressControls("aviation", () => aviationAudio);
  };

  if (toggle) toggle.addEventListener("click", () => {
    toggleFn();
    timelineBinder();
  });
  if (prev) prev.addEventListener("click", () => {
    prevFn();
    timelineBinder();
  });
  if (next) next.addEventListener("click", () => {
    nextFn();
    timelineBinder();
  });
  if (slider) {
    slider.addEventListener("input", (event) => {
      applyMusicVolume(kind, Number(event.target.value) / 100);
    });
    syncMusicSlider(kind);
  }
}


