function getProvinceNeighborPool(plate) {
  const neighborPlates = provinceNeighbors[plate] || [];
  return neighborPlates
    .map(neighborPlate => plateData.find(item => item.plate === neighborPlate))
    .filter(Boolean);
}

function initializeProvinceGame(setup) {
  if (!setup) {
    renderHome();
    return;
  }

  stopUniversalMusic();
  stopAviationMusic();
  setTopbar("📍 İl Tahmin Etme", "", "center");
  setFullscreenButtonVisible(false);

  const selectedCities = buildQuestionSet(plateData, setup.questionLimit);

  currentGame = {
    type: "province",
    sourceQuestions: [...plateData],
    questions: selectedCities,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedCities.length).fill(null),
    optionsCache: {},
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: false,
    highScore: getHighScore("province")
  };

  startUniversalMusic("province");
  renderProvinceGame();
}

async function startProvinceGame() {
  const setup = await requestGameSetup(plateData.length);
  initializeProvinceGame(setup);
}

function restartProvinceGame() {
  const previousGame = currentGame && currentGame.type === "province" ? currentGame : null;
  const fallbackName = previousGame?.playerName || getSavedPlayerName() || "Oyuncu";
  const fallbackLimit = Number(previousGame?.questionLimit) || 25;

  initializeProvinceGame({
    playerName: fallbackName,
    questionLimit: Math.min(fallbackLimit, plateData.length),
    isInfinite: false
  });
}

function buildProvinceOptions(correctItem) {
  const neighborPool = getProvinceNeighborPool(correctItem.plate)
    .filter(item => item && item.plate !== correctItem.plate && item.city !== correctItem.city);

  const wrongOptions = [];

  shuffleArray([...neighborPool]).forEach(item => {
    if (wrongOptions.length < 5 && !wrongOptions.includes(item.city)) {
      wrongOptions.push(item.city);
    }
  });

  if (wrongOptions.length < 5) {
    shuffleArray([...plateData]).forEach(item => {
      if (
        wrongOptions.length < 5 &&
        item.plate !== correctItem.plate &&
        item.city !== correctItem.city &&
        !wrongOptions.includes(item.city)
      ) {
        wrongOptions.push(item.city);
      }
    });
  }

  return shuffleArray([correctItem.city, ...wrongOptions.slice(0, 5)]);
}


const neighborProvinceQuestionPool = [...plateData];

function initializeNeighborProvinceGame(setup) {
  if (!setup) {
    renderHome();
    return;
  }

  stopGeographyMusic();
  stopAviationMusic();
  setTopbar("📍 İl Tahmin Etme", "", "center");

  const selectedCities = buildQuestionSet(neighborProvinceQuestionPool, setup.questionLimit);

  currentGame = {
    type: "neighborprovince",
    sourceQuestions: [...neighborProvinceQuestionPool],
    questions: selectedCities,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedCities.length).fill(null),
    optionsCache: {},
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: false,
    highScore: getHighScore("neighborprovince")
  };

  startUniversalMusic("neighborprovince");
  renderNeighborProvinceGame();
}

async function startNeighborProvinceGame() {
  const setup = await requestGameSetup(neighborProvinceQuestionPool.length);
  initializeNeighborProvinceGame(setup);
}

function restartNeighborProvinceGame() {
  const previousGame = currentGame && currentGame.type === "neighborprovince" ? currentGame : null;
  const fallbackName = previousGame?.playerName || getSavedPlayerName() || "Oyuncu";
  const fallbackLimit = Number(previousGame?.questionLimit) || 25;

  initializeNeighborProvinceGame({
    playerName: fallbackName,
    questionLimit: Math.min(fallbackLimit, neighborProvinceQuestionPool.length),
    isInfinite: false
  });
}

function restartProvinceLikeGame(forceType = null) {
  clearAnswerAdvanceTimer();
  const activeType = forceType || currentGame?.type;
  if (activeType === "province") return restartProvinceGame();
  if (activeType === "neighborprovince") return restartNeighborProvinceGame();
}

function buildNeighborProvinceOptions(correctItem) {
  const neighborPool = shuffleArray(
    getProvinceNeighborPool(correctItem.plate)
      .filter(item => item && item.plate !== correctItem.plate && item.city !== correctItem.city)
  );

  const wrongOptions = [];
  neighborPool.forEach(item => {
    if (wrongOptions.length < 3 && !wrongOptions.includes(item.city)) {
      wrongOptions.push(item.city);
    }
  });

  if (wrongOptions.length < 3) {
    const fallbackPool = shuffleArray([...plateData].filter(item => item && item.plate !== correctItem.plate && item.city !== correctItem.city));
    fallbackPool.forEach(item => {
      if (wrongOptions.length < 3 && !wrongOptions.includes(item.city)) {
        wrongOptions.push(item.city);
      }
    });
  }

  if (wrongOptions.length < 3) {
    return shuffleArray([correctItem.city, ...wrongOptions]).slice(0, Math.min(4, wrongOptions.length + 1));
  }

  return shuffleArray([correctItem.city, ...wrongOptions]);
}

function selectNeighborProvinceAnswer(option) {
  const game = currentGame;
  if (!game || game.type !== "neighborprovince") return;

  const currentValue = game.selectedAnswers[game.currentQuestion];
  if (isAnsweredValue(currentValue) || isSkippedAnswer(currentValue)) return;

  const currentItem = game.questions[game.currentQuestion];
  game.selectedAnswers[game.currentQuestion] = option;

  if (option === currentItem.city) {
    playCorrectSound();
    game.score += 10;
  } else {
    playWrongSound();
    game.score -= 5;
  }

  updateHighScore(game);
  renderNeighborProvinceGame();
  scheduleAutoAdvance(game, renderNeighborProvinceGame, renderNeighborProvinceResult, option === currentItem.city);
}

function bindNeighborProvinceEvents() {
  const game = currentGame;
  if (!game || game.type !== "neighborprovince") return;

  const backBtn = document.getElementById("back-home");
  if (backBtn) backBtn.addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });
  bindUniversalMusicControls("neighborprovince");
  bindAutoAdvanceToggle();

  const prevBtn = document.getElementById("prev-btn");
  if (prevBtn) {
    prevBtn.addEventListener("click", () => {
      if (game.currentQuestion > 0) {
        game.currentQuestion -= 1;
        renderNeighborProvinceGame();
      }
    });
  }

  const nextBtn = document.getElementById("next-btn");
  if (nextBtn) nextBtn.addEventListener("click", () => handleNextQuestion(game, renderNeighborProvinceGame, renderNeighborProvinceResult));

  const skipBtn = document.getElementById("skip-btn");
  if (skipBtn) skipBtn.addEventListener("click", () => handleSkipQuestion(game, renderNeighborProvinceGame, renderNeighborProvinceResult));

  const finishBtn = document.getElementById("finish-btn");
  if (finishBtn) {
    finishBtn.disabled = false;
    finishBtn.removeAttribute("disabled");
    finishBtn.addEventListener("click", (event) => {
      event.preventDefault();
      event.stopPropagation();
      finishNeighborProvinceGame();
    });
    finishBtn.addEventListener("touchend", (event) => {
      event.preventDefault();
      event.stopPropagation();
      finishNeighborProvinceGame();
    }, { passive: false });
  }

  document.querySelectorAll(".neighbor-province-option-btn").forEach((button) => {
    button.addEventListener("click", () => {
      selectNeighborProvinceAnswer(button.dataset.option);
    });
  });
}

function renderNeighborProvinceGame() {
  const game = currentGame;
  if (!game || game.type !== "neighborprovince") return;

  const currentItem = game.questions[game.currentQuestion];
  if (!currentItem) {
    renderNeighborProvinceResult();
    return;
  }

  const selected = game.selectedAnswers[game.currentQuestion];
  const answered = isAnsweredValue(selected);
  const skipped = isSkippedAnswer(selected);

  if (!game.optionsCache[game.currentQuestion]) {
    game.optionsCache[game.currentQuestion] = buildNeighborProvinceOptions(currentItem);
  }

  const options = game.optionsCache[game.currentQuestion];

  const optionButtons = options.map((option) => {
    const classes = ["neighbor-province-option-btn", "province-option-btn"];
    const disabled = answered || skipped ? "disabled" : "";

    if (answered) {
      if (option === currentItem.city) classes.push("correct");
      if (option === selected && option !== currentItem.city) classes.push("wrong");
    }

    return `<button type="button" class="${classes.join(" ")}" data-option="${option.replace(/"/g, '&quot;')}" ${disabled}>${option}</button>`;
  }).join("");

  appScreen.innerHTML = `
    <div class="game-toolbar">
      <button class="secondary-btn menu-btn small-menu-btn" id="back-home">← Menü</button>
      <div class="toolbar-badge">📍 İl Tahmin Etme</div>
    </div>

    ${renderUniversalMusicBar("neighborprovince")}

    ${renderStatsRow(game)}

    <div class="progress-area compact-progress">
      <div class="progress-bar">
        <div class="progress-fill" style="width:${getQuestionProgressPercent(game)}%"></div>
      </div>
    </div>

    ${renderPlateMap()}

    <section class="question-card province-question-card">
      <div class="question-chip">İl Tahmin Etme</div>
      <h2>Haritada parlayan il hangisidir?</h2>
      <div class="answers plate-answers" id="answers-container">
        ${optionButtons}
      </div>
    </section>

    ${renderQuestionNav(game, "Oyunu Bitir")}
  `;

  loadTurkeyMap(currentItem.plate);
  bindNeighborProvinceEvents();

  const finishBtn = document.getElementById("finish-btn");
  if (finishBtn) {
    finishBtn.disabled = false;
    finishBtn.removeAttribute("disabled");
  }
}

function renderNeighborProvinceResult() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game || game.type !== "neighborprovince") return;

  game.finishedAt = game.finishedAt || Date.now();

  const total = game.questions.length * 10;
  const counts = getGameCounts(game);
  const skippedCount = (game.selectedAnswers || []).filter(answer => isSkippedAnswer(answer)).length;
  const answeredCount = counts.correct + counts.wrong;
  const accuracy = answeredCount ? Math.round((counts.correct / answeredCount) * 100) : 0;

  game.correctCount = counts.correct;
  game.wrongCount = counts.wrong;
  saveGameResult(game);

  const high = getHighScoreLabel(game.type);
  const leaderboard = getLeaderboard(game.type);
  const leaderboardRows = leaderboard.length
    ? leaderboard.slice(0, 10).map((item, index) => `
        <tr>
          <td>${index + 1}</td>
          <td>${item.playerName}</td>
          <td>${item.score}</td>
          <td>${item.correct}</td>
          <td>${item.wrong}</td>
        </tr>
      `).join("")
    : `<tr><td colspan="5" class="leaderboard-empty">Henüz skor yok.</td></tr>`;

  let message = "Komşu illeri daha iyi ayırmaya başladığında skorun hızlı yükselir.";
  if (game.score === total) {
    message = "Mükemmel sonuç. Komşu il mantığını kusursuz çözmüşsün.";
  } else if (game.score >= total * 0.6) {
    message = "Gayet iyi performans. Birkaç tekrar daha yaparsan çok daha iyi olur.";
  }

  const reviewCards = game.questions.map((question, index) => {
    const selected = game.selectedAnswers[index];
    const isSkipped = isSkippedAnswer(selected);
    const isCorrect = selected === question.city;

    let stateClass = "province-review-unanswered";
    let stateLabel = "Boş";
    let answerText = "Cevap verilmedi";

    if (isSkipped) {
      stateClass = "province-review-skipped";
      stateLabel = "Pas";
      answerText = "Pas geçildi";
    } else if (isAnsweredValue(selected)) {
      stateClass = isCorrect ? "province-review-correct" : "province-review-wrong";
      stateLabel = isCorrect ? "Doğru" : "Yanlış";
      answerText = selected;
    }

    return `
      <div class="province-review-card ${stateClass}">
        <div class="province-review-top">
          <span class="province-review-index">Soru ${index + 1}</span>
          <span class="province-review-state">${stateLabel}</span>
        </div>
        <div class="province-review-city">Doğru cevap: ${question.city}</div>
        <div class="province-review-answer">Senin cevabın: ${answerText}</div>
      </div>
    `;
  }).join("");

  appScreen.innerHTML = `
    <div class="result-box result-box-enhanced province-result-box">
      <div class="result-actions result-actions-top">
        <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      </div>

      <h2>İl Tahmin Etme Tamamlandı</h2>
      <p class="result-score">Toplam Puanın: <strong>${game.score} / ${total}</strong></p>

      <div class="result-stats-grid result-stats-grid-large province-result-stats">
        <div class="result-stat-pill"><span>Oyuncu</span><strong>${game.playerName || "-"}</strong></div>
        <div class="result-stat-pill"><span>Doğru</span><strong>${counts.correct}</strong></div>
        <div class="result-stat-pill"><span>Yanlış</span><strong>${counts.wrong}</strong></div>
        <div class="result-stat-pill"><span>Pas</span><strong>${skippedCount}</strong></div>
        <div class="result-stat-pill"><span>Başarı</span><strong>%${accuracy}</strong></div>
        <div class="result-stat-pill"><span>En Yüksek</span><strong>${high.score}</strong><em>${high.playerName}</em></div>
      </div>

      <p class="result-message">${message}</p>

      <div class="leaderboard-panel">
        <h3>Skor Tablosu</h3>
        <div class="leaderboard-table-wrap">
          <table class="leaderboard-table">
            <thead>
              <tr>
                <th>#</th>
                <th>Oyuncu</th>
                <th>Puan</th>
                <th>Doğru</th>
                <th>Yanlış</th>
              </tr>
            </thead>
            <tbody>${leaderboardRows}</tbody>
          </table>
        </div>
      </div>

      <div class="province-review-section">
        <h3>Cevap Özeti</h3>
        <div class="province-review-grid">
          ${reviewCards}
        </div>
      </div>
    </div>
  `;

  const backBtn = document.getElementById("back-home");
  if (backBtn) backBtn.addEventListener("click", renderHome);
}

function goToPreviousProvinceQuestion() {
  const game = currentGame;
  if (!game || game.type !== "province") return;
  if (game.currentQuestion <= 0) return;
  game.currentQuestion -= 1;
  renderProvinceGame();
}

function goToNextProvinceQuestion() {
  const game = currentGame;
  if (!game || game.type !== "province") return;
  if (!canMoveNext(game)) return;

  if (game.currentQuestion >= game.questions.length - 1) {
    renderProvinceResult();
    return;
  }

  game.currentQuestion += 1;
  renderProvinceGame();
}

function skipProvinceQuestion() {
  const game = currentGame;
  if (!game || game.type !== "province") return;

  const currentValue = game.selectedAnswers[game.currentQuestion];
  if (isAnsweredValue(currentValue) || isSkippedAnswer(currentValue)) return;

  game.score -= 2;
  game.selectedAnswers[game.currentQuestion] = "__SKIPPED__";
  updateHighScore(game);

  if (game.currentQuestion >= game.questions.length - 1) {
    renderProvinceGame();
    return;
  }

  game.currentQuestion += 1;
  renderProvinceGame();
}

function selectProvinceAnswer(option) {
  const game = currentGame;
  if (!game || game.type !== "province") return;

  const currentValue = game.selectedAnswers[game.currentQuestion];
  if (isAnsweredValue(currentValue) || isSkippedAnswer(currentValue)) return;

  const currentItem = game.questions[game.currentQuestion];
  game.selectedAnswers[game.currentQuestion] = option;

  if (option === currentItem.city) {
    playCorrectSound();
    game.score += 10;
  } else {
    playWrongSound();
    game.score -= 5;
  }

  updateHighScore(game);
  renderProvinceGame();
  scheduleAutoAdvance(game, renderProvinceGame, renderProvinceResult, option === currentItem.city);
}

