const HIGH_SCORE_KEYS = {
  flag: "quizHighScore_flag",
  aviation: "quizHighScore_aviation",
  geography: "quizHighScore_geography",
  plate: "quizHighScore_plate",
  province: "quizHighScore_province",
  neighborprovince: "quizHighScore_neighborprovince",
  capital: "quizHighScore_capital",
  delta: "quizHighScore_delta"
};

function getHighScore(gameType) {
  try {
    const key = HIGH_SCORE_KEYS[gameType];
    if (!key) return 0;
    const saved = Number(localStorage.getItem(key));
    return Number.isFinite(saved) && saved > 0 ? saved : 0;
  } catch (error) {
    return 0;
  }
}

function setHighScore(gameType, score) {
  try {
    const key = HIGH_SCORE_KEYS[gameType];
    if (!key) return score;
    const currentHighScore = getHighScore(gameType);
    const nextHighScore = Math.max(currentHighScore, score);
    localStorage.setItem(key, String(nextHighScore));
    return nextHighScore;
  } catch (error) {
    return Math.max(getHighScore(gameType), score);
  }
}

function updateHighScore(game) {
  if (!game) return 0;
  game.highScore = setHighScore(game.type, game.score);
  return game.highScore;
}

