async function startDeltaGame() {
  const playerName = await getPlayerName();
  if (!playerName) {
    renderHome();
    return;
  }

  const setup = {
    playerName,
    questionLimit: deltaData.length,
    isInfinite: false
  };

  stopGeographyMusic();
  stopAviationMusic();
  setTopbar("🌊 Delta Ovası Bulma", "", "center");
  setFullscreenButtonVisible(false);

  const selectedDeltas = buildQuestionSet(deltaData, setup.questionLimit);

  currentGame = {
    type: "delta",
    sourceQuestions: [...deltaData],
    questions: selectedDeltas,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedDeltas.length).fill(null),
    optionsCache: {},
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: setup.isInfinite,
    highScore: getHighScore("delta")
  };

  startUniversalMusic("delta");
  renderDeltaGame();
}

function restartDeltaGame() {
  const previousGame = currentGame && currentGame.type === "delta" ? currentGame : null;
  const fallbackName = previousGame?.playerName || getSavedPlayerName() || "Oyuncu";
  const fallbackLimit = Number(previousGame?.questionLimit) || 10;

  currentGame = null;
  initializeDeltaGame({
    playerName: fallbackName,
    questionLimit: Math.min(fallbackLimit, deltaData.length),
    isInfinite: false
  });
}

function initializeDeltaGame(setup) {
  if (!setup) {
    renderHome();
    return;
  }

  stopGeographyMusic();
  stopAviationMusic();
  setTopbar("🌊 Delta Ovası Bulma", "", "center");
  setFullscreenButtonVisible(false);

  const selectedDeltas = buildQuestionSet(deltaData, setup.questionLimit);

  currentGame = {
    type: "delta",
    sourceQuestions: [...deltaData],
    questions: selectedDeltas,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedDeltas.length).fill(null),
    optionsCache: {},
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: false,
    highScore: getHighScore("delta")
  };

  renderDeltaGame();
}

function buildDeltaOptions(correctItem) {
  const sameRegion = shuffleArray(deltaData.filter(item => item.id !== correctItem.id && item.region === correctItem.region));
  const fallback = shuffleArray(deltaData.filter(item => item.id !== correctItem.id && item.region !== correctItem.region));
  const wrong = [];

  [...sameRegion, ...fallback].forEach(item => {
    if (wrong.length < 3 && !wrong.includes(item.name)) wrong.push(item.name);
  });

  return shuffleArray([correctItem.name, ...wrong]).slice(0, 4);
}

function renderDeltaMapCard() {
  return `
    <section class="map-card delta-map-card">
      <div class="map-card-title">İşaretli konumu dikkatle incele</div>
      <div class="svg-map-wrapper compact-map-wrapper delta-map-shell" id="delta-map-shell">
        <div class="map-loading">Harita yükleniyor...</div>
      </div>
    </section>
  `;
}

function loadDeltaMap(deltaItem) {
  const mapWrapper = document.getElementById("delta-map-shell");
  if (!mapWrapper || !deltaItem) return;

  try {
    const markerX = Number(deltaItem.x) || 0;
    const markerY = Number(deltaItem.y) || 0;

    mapWrapper.innerHTML = `
      <div class="delta-map-figure" aria-hidden="true">
        <div class="delta-map-base">
          ${turkeySvgInline}
        </div>
        <svg class="delta-overlay-svg" viewBox="0 0 1000 422" preserveAspectRatio="xMidYMid meet" aria-hidden="true">
          <g class="delta-svg-pin" transform="translate(${markerX} ${markerY})">
            <circle class="delta-svg-ring delta-svg-ring-one" cx="0" cy="0" r="11"></circle>
            <circle class="delta-svg-ring delta-svg-ring-two" cx="0" cy="0" r="20"></circle>
            <path class="delta-svg-stem" d="M0 8 L0 28"></path>
            <circle class="delta-svg-core" cx="0" cy="0" r="7"></circle>
            <circle class="delta-svg-shine" cx="-2.4" cy="-2.2" r="2.1"></circle>
          </g>
        </svg>
      </div>
    `;

    const svgElement = mapWrapper.querySelector(".delta-map-base svg");
    if (!svgElement) throw new Error("SVG içeriği okunamadı.");

    svgElement.classList.add("turkey-map-svg", "delta-map-svg");
    svgElement.setAttribute("preserveAspectRatio", "xMidYMid meet");
    svgElement.style.pointerEvents = "none";
    svgElement.querySelectorAll("*").forEach(node => {
      node.style.pointerEvents = "none";
    });
  } catch (error) {
    mapWrapper.innerHTML = `<div class="map-loading">Harita yüklenemedi.</div>`;
    console.error("Delta haritası yükleme hatası:", error);
  }
}

function selectDeltaAnswer(option) {
  const game = currentGame;
  if (!game || game.type !== "delta") return;

  const currentValue = game.selectedAnswers[game.currentQuestion];
  if (isAnsweredValue(currentValue) || isSkippedAnswer(currentValue)) return;

  const currentItem = game.questions[game.currentQuestion];
  game.selectedAnswers[game.currentQuestion] = option;

  if (option === currentItem.name) {
    playCorrectSound();
    game.score += 10;
  } else {
    playWrongSound();
    game.score -= 5;
  }

  updateHighScore(game);
  renderDeltaGame();
  scheduleAutoAdvance(game, renderDeltaGame, renderDeltaResult, option === currentItem.name);
}

function bindDeltaEvents() {
  const game = currentGame;
  if (!game || game.type !== "delta") return;

  const backBtn = document.getElementById("back-home");
  if (backBtn) backBtn.addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });

  bindUniversalMusicControls("delta");
  bindAutoAdvanceToggle();

  const prevBtn = document.getElementById("prev-btn");
  if (prevBtn) {
    prevBtn.addEventListener("click", () => {
      if (game.currentQuestion > 0) {
        game.currentQuestion -= 1;
        renderDeltaGame();
      }
    });
  }

  const nextBtn = document.getElementById("next-btn");
  if (nextBtn) nextBtn.addEventListener("click", () => handleNextQuestion(game, renderDeltaGame, renderDeltaResult));

  const skipBtn = document.getElementById("skip-btn");
  if (skipBtn) skipBtn.addEventListener("click", () => handleSkipQuestion(game, renderDeltaGame, renderDeltaResult));

  const finishBtn = document.getElementById("finish-btn");
  if (finishBtn) finishBtn.addEventListener("click", renderDeltaResult);

  document.querySelectorAll(".delta-option-btn").forEach((button) => {
    button.addEventListener("click", () => selectDeltaAnswer(button.dataset.option));
  });
}

function renderDeltaGame() {
  const game = currentGame;
  if (!game || game.type !== "delta") return;

  const currentItem = game.questions[game.currentQuestion];
  if (!currentItem) {
    renderDeltaResult();
    return;
  }

  const selected = game.selectedAnswers[game.currentQuestion];
  const answered = isAnsweredValue(selected);
  const skipped = isSkippedAnswer(selected);

  if (!game.optionsCache[game.currentQuestion]) {
    game.optionsCache[game.currentQuestion] = buildDeltaOptions(currentItem);
  }

  const options = game.optionsCache[game.currentQuestion];
  const optionButtons = options.map((option) => {
    const classes = ["delta-option-btn"];
    const disabled = answered || skipped ? "disabled" : "";

    if (answered) {
      if (option === currentItem.name) classes.push("correct");
      if (option === selected && option !== currentItem.name) classes.push("wrong");
    }

    return `<button type="button" class="${classes.join(" ")}" data-option="${option.replace(/"/g, '&quot;')}" ${disabled}>${option}</button>`;
  }).join("");

  const feedbackHtml = answered ? `
    <div class="delta-info-strip ${selected === currentItem.name ? "is-correct" : "is-wrong"}">
      <strong>${currentItem.name}</strong> · ${currentItem.river} · ${currentItem.locationHint}
    </div>
  ` : `
    
    </div>
  `;

  appScreen.innerHTML = `
    <div class="game-toolbar">
      <button class="secondary-btn menu-btn small-menu-btn" id="back-home">← Menü</button>
      <div class="toolbar-badge">🌊 Delta Ovası Bulma</div>
    </div>

    ${renderUniversalMusicBar("delta")}

    ${renderStatsRow(game)}

    <div class="progress-area compact-progress">
      <div class="progress-bar">
        <div class="progress-fill" style="width:${getQuestionProgressPercent(game)}%"></div>
      </div>
    </div>

    ${renderDeltaMapCard()}

    <section class="question-card province-question-card delta-question-card">
      <div class="question-chip">Türkiye Harita Oyunu</div>
      <h2>Haritada işaretlenen delta ovası hangisidir?</h2>
      ${feedbackHtml}
      <div class="answers plate-answers" id="answers-container">
        ${optionButtons}
      </div>
    </section>

    ${renderQuestionNav(game, "Oyunu Bitir")}
  `;

  loadDeltaMap(currentItem);
  bindDeltaEvents();
}

function renderDeltaResult() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game || game.type !== "delta") return;

  updateHighScore(game);
  const total = game.questions.length * 10;

  let message = "Delta ovalarını birkaç tekrar daha yaparsan harita üstünde çok daha hızlı ayırt edebilirsin.";
  if (game.score === total) message = "Mükemmel sonuç. Türkiye'nin başlıca delta ovalarını çok iyi biliyorsun.";
  else if (game.score >= total * 0.6) message = "Gayet iyi performans. Harita üzerinde konumları büyük ölçüde oturtmuşsun.";

  appScreen.innerHTML = renderResultSummary("Delta Ovası Bulma Tamamlandı", game, total, message, "restart-delta");

  document.getElementById("restart-delta").addEventListener("click", restartDeltaGame);
  document.getElementById("back-home").addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });
}

