const ENGLISH_WORD_THEME_LABELS = {
  easy: "Günlük kelimeler",
  medium: "Orta seviye kelimeler",
  hard: "Zor seviye kelimeler",
  mixed: "1500 kelimelik karma havuz"
};

function getEnglishWordPools() {
  const source = typeof ENGLISH_WORD_BANK !== "undefined" ? ENGLISH_WORD_BANK : {};
  const buildLevel = (levelKey) => {
    const categories = source[levelKey] || {};
    const questionPool = [];
    Object.entries(categories).forEach(([category, items]) => {
      (items || []).forEach((item, index) => {
        questionPool.push({
          id: `${levelKey}-${category}-${index}`,
          word: item.word,
          meaning: item.meaning,
          category,
          level: levelKey
        });
      });
    });
    return questionPool;
  };

  const easy = buildLevel("easy");
  const medium = buildLevel("medium");
  const hard = buildLevel("hard");

  return {
    easy,
    medium,
    hard,
    mixed: shuffleArray([...easy, ...medium, ...hard])
  };
}

function buildEnglishWordOptions(correctItem, questionPool) {
  const byCategory = shuffleArray(
    questionPool.filter(item => item.id !== correctItem.id && item.category === correctItem.category && item.meaning !== correctItem.meaning)
  );
  const byLevel = shuffleArray(
    questionPool.filter(item => item.id !== correctItem.id && item.level === correctItem.level && item.meaning !== correctItem.meaning)
  );
  const fallback = shuffleArray(
    [...questionPool].filter(item => item.id !== correctItem.id && item.meaning !== correctItem.meaning)
  );

  const wrongOptions = [];
  [...byCategory, ...byLevel, ...fallback].forEach((item) => {
    if (wrongOptions.length < 3 && !wrongOptions.includes(item.meaning)) {
      wrongOptions.push(item.meaning);
    }
  });

  return shuffleArray([correctItem.meaning, ...wrongOptions.slice(0, 3)]);
}

async function startEnglishWordGame() {
  const pools = getEnglishWordPools();
  const totalCount = pools.mixed.length;
  const setup = await requestWordGameSetup(totalCount);
  if (!setup) {
    renderHome();
    return;
  }

  initializeEnglishWordGame(setup);
}

function initializeEnglishWordGame(setup) {
  if (!setup) {
    renderHome();
    return;
  }

  const pools = getEnglishWordPools();
  const difficulty = setup.difficulty || "mixed";
  const sourcePool = difficulty === "mixed" ? pools.mixed : (pools[difficulty] || pools.easy);
  const selectedQuestions = buildQuestionSet(sourcePool, setup.questionLimit);

  stopGeographyMusic();
  stopAviationMusic();
  setTopbar("🧠 İngilizce Kelime Bilme", `${ENGLISH_WORD_LEVEL_LABELS[difficulty]} seviye`, "center");
  setFullscreenButtonVisible(false);

  currentGame = {
    type: "englishword",
    sourceQuestions: [...sourcePool],
    questions: selectedQuestions,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedQuestions.length).fill(null),
    optionsCache: {},
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: false,
    difficulty,
    highScore: getHighScore("englishword")
  };

  startUniversalMusic("englishword");
  renderEnglishWordGame();
}

function restartEnglishWordGame() {
  const previousGame = currentGame && currentGame.type === "englishword" ? currentGame : null;
  const fallbackName = previousGame?.playerName || getSavedPlayerName() || "Oyuncu";
  const fallbackLimit = Number(previousGame?.questionLimit) || 25;
  const fallbackDifficulty = previousGame?.difficulty || "mixed";
  const pools = getEnglishWordPools();
  const activePool = fallbackDifficulty === "mixed" ? pools.mixed : (pools[fallbackDifficulty] || pools.easy);

  initializeEnglishWordGame({
    playerName: fallbackName,
    questionLimit: Math.min(fallbackLimit, activePool.length),
    isInfinite: false,
    difficulty: fallbackDifficulty
  });
}

function renderEnglishWordGame() {
  const game = currentGame;
  const currentItem = game.questions[game.currentQuestion];
  const selected = game.selectedAnswers[game.currentQuestion];
  const answered = isAnsweredValue(selected);

  if (!game.optionsCache[game.currentQuestion]) {
    game.optionsCache[game.currentQuestion] = buildEnglishWordOptions(currentItem, game.sourceQuestions);
  }

  const options = game.optionsCache[game.currentQuestion];

  appScreen.innerHTML = `
    <div class="game-toolbar">
      <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      <div class="toolbar-badge">🧠 İngilizce Kelime Bilme</div>
    </div>

    ${renderUniversalMusicBar("englishword")}

    ${renderStatsRow(game)}

    <div class="progress-area">
      <div class="progress-bar">
        <div class="progress-fill" style="width:${getQuestionProgressPercent(game)}%"></div>
      </div>
    </div>

    <section class="question-card english-word-card">
      <div class="question-kicker">${ENGLISH_WORD_LEVEL_LABELS[game.difficulty]} Seviye · ${ENGLISH_WORD_THEME_LABELS[game.difficulty]}</div>
      <div class="english-word-focus">${currentItem.word}</div>
      <h2>Bu İngilizce kelimenin doğru Türkçe anlamı hangisidir?</h2>
      <div class="english-word-subtitle">Birbirine yakın 4 seçenekten yalnızca biri doğrudur.</div>
      <div class="answers english-word-answers" id="answers-container"></div>
    </section>

    ${renderQuestionNav(game, "Testi Bitir")}
  `;

  const answersContainer = document.getElementById("answers-container");

  options.forEach(option => {
    const button = document.createElement("button");
    button.textContent = option;
    button.className = "";

    if (answered) {
      if (option === currentItem.meaning) button.classList.add("correct");
      if (option === selected && option !== currentItem.meaning) button.classList.add("wrong");
      button.disabled = true;
    }

    button.addEventListener("click", () => {
      if (isAnsweredValue(game.selectedAnswers[game.currentQuestion])) return;

      game.selectedAnswers[game.currentQuestion] = option;

      if (option === currentItem.meaning) {
        playCorrectSound();
        game.score += 10;
      } else {
        playWrongSound();
        game.score -= 5;
      }

      updateHighScore(game);
      renderEnglishWordGame();
      scheduleAutoAdvance(game, renderEnglishWordGame, renderEnglishWordResult, option === currentItem.meaning);
    });

    answersContainer.appendChild(button);
  });

  document.getElementById("back-home").addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });
  bindUniversalMusicControls("englishword");
  bindAutoAdvanceToggle();

  const prevBtn = document.getElementById("prev-btn");
  if (prevBtn) {
    prevBtn.addEventListener("click", () => {
      if (game.currentQuestion > 0) {
        game.currentQuestion--;
        renderEnglishWordGame();
      }
    });
  }

  const nextBtn = document.getElementById("next-btn");
  if (nextBtn) nextBtn.addEventListener("click", () => handleNextQuestion(game, renderEnglishWordGame, renderEnglishWordResult));

  const skipBtn = document.getElementById("skip-btn");
  if (skipBtn) skipBtn.addEventListener("click", () => handleSkipQuestion(game, renderEnglishWordGame, renderEnglishWordResult));

  const finishBtn = document.getElementById("finish-btn");
  if (finishBtn) finishBtn.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    renderEnglishWordResult();
  });
}

function renderEnglishWordResult() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  updateHighScore(game);
  const total = game.questions.length * 10;

  let message = "Kelime bilgin gelişiyor. Düzenli tekrar ile çok daha hızlı yükselirsin.";
  if (game.score === total) message = "Mükemmel sonuç. Kelime haznen gerçekten çok güçlü.";
  else if (game.score >= total * 0.6) message = "Gayet iyi performans. İngilizce kelime hakimiyetin oturuyor.";

  appScreen.innerHTML = renderResultSummary("İngilizce Kelime Bilme Tamamlandı", game, total, message, "restart-english-word");

  document.getElementById("restart-english-word").addEventListener("click", restartEnglishWordGame);
  document.getElementById("back-home").addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });
}

