async function startAviationGame() {
  const setup = await requestGameSetup(aviationQuestions.length);
  if (!setup) {
    renderHome();
    return;
  }
  stopGeographyMusic();

  setTopbar("✈ Havacılık Testi", "Teknik bilgi ve temel uçuş soruları", "center");
  setFullscreenButtonVisible(false);

  const selectedQuestions = buildQuestionSet(aviationQuestions, setup.questionLimit);

  currentGame = {
    type: "aviation",
    sourceQuestions: [...aviationQuestions],
    questions: selectedQuestions,
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedQuestions.length).fill(null),
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: setup.isInfinite,
    highScore: getHighScore("aviation")
  };

  stopAviationMusic();
  startUniversalMusic("aviation");

  renderAviationGame();
}

function renderAviationGame() {
  const game = currentGame;
  const q = game.questions[game.currentQuestion];
  const selected = game.selectedAnswers[game.currentQuestion];
  const answered = isAnsweredValue(selected);

  appScreen.innerHTML = `
    <div class="game-toolbar">
      <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      <div class="toolbar-badge">✈ Havacılık Testi</div>
    </div>

    ${renderUniversalMusicBar("aviation")}

    ${renderStatsRow(game)}

    <div class="progress-area">
      <div class="progress-bar">
        <div class="progress-fill" style="width:${getQuestionProgressPercent(game)}%"></div>
      </div>
    </div>

    <section class="question-card">
      <h2>${q.question}</h2>
      <div class="answers" id="answers-container"></div>
    </section>

    ${renderQuestionNav(game, "Testi Bitir")}
  `;

  const answersContainer = document.getElementById("answers-container");

  q.answers.forEach((answer, index) => {
    const button = document.createElement("button");
    button.textContent = answer;

    if (answered) {
      if (index === q.correct) button.classList.add("correct");
      if (index === selected && index !== q.correct) button.classList.add("wrong");
      button.disabled = true;
    }

    button.addEventListener("click", () => {
      if (isAnsweredValue(game.selectedAnswers[game.currentQuestion])) return;

      game.selectedAnswers[game.currentQuestion] = index;

      if (index === q.correct) {
        playCorrectSound();
        game.score += 10;
      } else {
        playWrongSound();
        game.score -= 5;
      }

      updateHighScore(game);
      renderAviationGame();
      scheduleAutoAdvance(game, renderAviationGame, renderAviationResult, index === q.correct);
    });

    answersContainer.appendChild(button);
  });

  document.getElementById("back-home").addEventListener("click", () => {
    stopUniversalMusic();
    renderHome();
  });

  const prevBtn = document.getElementById("prev-btn");
  if (prevBtn) {
    prevBtn.addEventListener("click", () => {
      if (game.currentQuestion > 0) {
        game.currentQuestion--;
        renderAviationGame();
      }
    });
  }

  const nextBtn = document.getElementById("next-btn");
  if (nextBtn) nextBtn.addEventListener("click", () => handleNextQuestion(game, renderAviationGame, renderAviationResult));

  const skipBtn = document.getElementById("skip-btn");
  if (skipBtn) skipBtn.addEventListener("click", () => handleSkipQuestion(game, renderAviationGame, renderAviationResult));

  const finishBtn = document.getElementById("finish-btn");
  if (finishBtn) finishBtn.addEventListener("click", (event) => {
    event.preventDefault();
    event.stopPropagation();
    finishAviationGame();
  });

  bindUniversalMusicControls("aviation");
}

function renderAviationResult() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game) return;

  updateHighScore(game);
  const total = game.questions.length * 10;

  let message = "Daha fazla pratik yapmalısın.";
  if (game.score === total) message = "Mükemmel performans.";
  else if (game.score >= total * 0.6) message = "İyi performans.";

  stopAviationMusic();

  appScreen.innerHTML = renderResultSummary("Havacılık Testi Tamamlandı", game, total, message, "restart-aviation");

  const restartBtn = document.getElementById("restart-aviation");
  const backHomeBtn = document.getElementById("back-home");

  if (restartBtn) {
    restartBtn.addEventListener("click", () => {
      startAviationGame();
    });
  }

  if (backHomeBtn) {
    backHomeBtn.addEventListener("click", () => {
      stopUniversalMusic();
      renderHome();
    });
  }
}

function finishAviationGame() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game || game.type !== "aviation") return;
  renderAviationResult();
}

function finishProvinceGame() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game || game.type !== "province") return;

  try {
    game.finishedAt = Date.now();
    renderProvinceResult();
  } catch (error) {
    console.error("Province result render failed:", error);
    appScreen.innerHTML = renderResultSummary(
      "İl Tahmin Etme Tamamlandı",
      game,
      game.questions.length * 10,
      "",
      "restart-province"
    );

    const restartBtn = document.getElementById("restart-province");
    if (restartBtn) restartBtn.remove();

    const backBtn = document.getElementById("back-home");
    if (backBtn) backBtn.addEventListener("click", renderHome);
  }
}

function finishNeighborProvinceGame() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  if (!game || game.type !== "neighborprovince") return;

  try {
    game.finishedAt = Date.now();
    renderNeighborProvinceResult();
  } catch (error) {
    console.error("Neighbor province result render failed:", error);
    appScreen.innerHTML = renderResultSummary(
      "İl Tahmin Etme Tamamlandı",
      game,
      game.questions.length * 10,
      "",
      "restart-neighbor-province"
    );

    const restartBtn = document.getElementById("restart-neighbor-province");
    if (restartBtn) restartBtn.remove();

    const backBtn = document.getElementById("back-home");
    if (backBtn) backBtn.addEventListener("click", renderHome);
  }
}

